        }

        // ── Parse arguments ───────────────────────────────────────────────────
        int    count      = 1;
        String customName = null;
        String worldName  = null;
        double coordX     = 0;
        double coordY     = 0;
        double coordZ     = 0;
        boolean spawnWithoutBody = false;

        boolean isConsole = !(sender instanceof Player);

        // Parse arguments differently for console vs player
        if (isConsole) {
            // Console syntax: /fpp spawn [count] [world [x,y,z]]
            // e.g., /fpp spawn 5
            // e.g., /fpp spawn 5 world
            // e.g., /fpp spawn 5 world 100,64,200
            if (args.length >= 1) {
                try {
                    count = Integer.parseInt(args[0]);
                    if (count <= 0) throw new NumberFormatException();
                } catch (NumberFormatException e) {
                    sender.sendMessage(Lang.get("spawn-invalid"));
                    return true;
                }
            }
            if (args.length >= 2) {
                worldName = args[1];
                World w = Bukkit.getWorld(worldName);
                if (w == null) {
                    sender.sendMessage(Lang.get("spawn-world-not-found", "world", worldName));
                    return true;
                }
            } else {
                // No world specified from console — spawn without body (tab-list only)
                spawnWithoutBody = true;
            }
            if (args.length >= 3) {
                // Parse x,y,z coordinates
                String coordStr = args[2];
                String[] coords = coordStr.split(",");
                if (coords.length != 3) {
                    sender.sendMessage(Lang.get("spawn-invalid-coords"));
                    return true;
                }
                try {
                    coordX = Double.parseDouble(coords[0]);
                    coordY = Double.parseDouble(coords[1]);
                    coordZ = Double.parseDouble(coords[2]);
                } catch (NumberFormatException e) {
                    sender.sendMessage(Lang.get("spawn-invalid-coords"));
                    return true;
                }
            }
        } else {
            // Player syntax: /fpp spawn [amount] [--name <name>] [--world <world>]
            for (int i = 0; i < args.length; i++) {
                switch (args[i].toLowerCase()) {
                    case "--name" -> {
                        if (i + 1 < args.length) {
                            customName = args[++i];
                        } else {
                            sender.sendMessage(Lang.get("spawn-invalid"));
                            return true;
                        }
                    }
                    case "--world" -> {
                        if (i + 1 < args.length) {
                            worldName = args[++i];
                        } else {
                            sender.sendMessage(Lang.get("spawn-invalid"));
                            return true;
                        }
                    }
                    default -> {
                        try {
                            count = Integer.parseInt(args[i]);
                            if (count <= 0) throw new NumberFormatException();
                        } catch (NumberFormatException e) {
                            sender.sendMessage(Lang.get("spawn-invalid"));
                            return true;
                        }
                    }
                }
            }
        }

        // ── Resolve spawn location ─────────────────────────────────────────────
        Location location;
        if (sender instanceof Player player) {
            location = player.getLocation();
            if (worldName != null) {
                World w = Bukkit.getWorld(worldName);
                if (w == null) {
                    sender.sendMessage(Lang.get("spawn-world-not-found", "world", worldName));
                    return true;
                }
                location = w.getSpawnLocation();
            }
        } else {
            // Console spawn
            if (worldName != null) {
                World w = Bukkit.getWorld(worldName);
                if (w == null) {
                    sender.sendMessage(Lang.get("spawn-world-not-found", "world", worldName));
                    return true;
                }
                // Use custom coordinates if provided, otherwise world spawn
                if (args.length >= 3) {
                    location = new Location(w, coordX, coordY, coordZ);
                } else {
                    location = w.getSpawnLocation();
                }
            } else {
                List<World> worlds = Bukkit.getWorlds();
                if (worlds.isEmpty()) {
                    sender.sendMessage(Lang.get("spawn-console-no-world"));
                    return true;
                }
                // Spawn without body — use dummy location (won't be used for body spawning)
                location = worlds.getFirst().getSpawnLocation();
            }
        }

        // ── User-tier spawn ────────────────────────────────────────────────────
        if (isUser) {
            if (!(sender instanceof Player player)) {
                sender.sendMessage(Lang.get("player-only"));
                return true;
            }

            // Cooldown check
            if (!Perm.has(sender, Perm.BYPASS_COOLDOWN) && manager.isOnCooldown(player.getUniqueId())) {
                long remaining = manager.getRemainingCooldown(player.getUniqueId());
                sender.sendMessage(Lang.get("spawn-cooldown", "seconds", String.valueOf(remaining)));
                return true;
            }

            // Enforce personal bot limit
            int permLimit    = Perm.resolveUserBotLimit(sender);
            int limit        = permLimit >= 0 ? permLimit : Config.userBotLimit();
            int alreadyOwned = manager.getBotsOwnedBy(player.getUniqueId()).size();
            if (alreadyOwned >= limit) {
                sender.sendMessage(Lang.get("spawn-user-limit-reached", "limit", String.valueOf(limit)));
                return true;
            }
            count = Math.min(count, limit - alreadyOwned);

            int result = manager.spawnUserBot(location, count, player, false);
            if (result == -1) {
                int max = Config.maxBots();
